static size_t safe_mul_size(size_t a, size_t b, int *ok) {
    if (!ok) return 0;
    if (a == 0 || b == 0) {
        *ok = 1;
        return 0;
    }
    if (a > SIZE_MAX / b) {
        *ok = 0;
        return 0;
    }
    *ok = 1;
    return a * b;
}

/* Copies token into fixed-size field buffer, ensuring NUL termination. */
static void copy_token_to_field(char *dst, size_t dst_size, const char *tok, size_t tok_len) {
    if (!dst || dst_size == 0) return;
    size_t n = (tok && tok_len < (dst_size - 1)) ? tok_len : (dst_size - 1);
    if (n > 0 && tok) {
        memcpy(dst, tok, n);
    }
    dst[n] = '\0';
    if (dst_size > n + 1) {
        memset(dst + n + 1, 0, dst_size - (n + 1));
    }
}

int parse_csv_records(int record_count, int* field_sizes, char** csv_data, char** parsed_buffer) {
    if (!parsed_buffer) return -1;
    *parsed_buffer = NULL;

    if (record_count <= 0 || !field_sizes || !csv_data) return -1;
    if (!csv_data[0]) return -1;

    int field_count = count_fields_in_record(csv_data[0]);
    if (field_count <= 0) return -1;

    /* Validate field sizes and compute per-record size. */
    size_t per_record_bytes = 0;
    for (int i = 0; i < field_count; i++) {
        if (field_sizes[i] <= 0) return -1;
        if ((size_t)field_sizes[i] > SIZE_MAX - per_record_bytes) return -1;
        per_record_bytes += (size_t)field_sizes[i];
    }

    int ok = 0;
    size_t total_bytes = safe_mul_size((size_t)record_count, per_record_bytes, &ok);
    if (!ok) return -1;
    if (total_bytes == 0) return -1;

    char *out = (char *)calloc(1, total_bytes);
    if (!out) return -1;

    /* Parse each record. */
    for (int r = 0; r < record_count; r++) {
        const char *line = csv_data[r];
        if (!line) {
            free(out);
            return -1;
        }

        const char *p = line;
        size_t offset = (size_t)r * per_record_bytes;

        for (int f = 0; f < field_count; f++) {
            const char *tok_start = p;

            while (*p && *p != ',') p++;
            const char *tok_end = p;

            size_t tok_len = (size_t)(tok_end - tok_start);

            char *field_dst = out + offset;
            size_t field_dst_size = (size_t)field_sizes[f];

            copy_token_to_field(field_dst, field_dst_size, tok_start, tok_len);

            offset += field_dst_size;

            /* Advance past delimiter if present. */
            if (*p == ',') p++;

            /* If record ended early, pad remaining fields with empty strings and stop. */
            if (*tok_end == '\0') {
                for (int ff = f + 1; ff < field_count; ff++) {
                    char *dst2 = out + offset;
                    size_t sz2 = (size_t)field_sizes[ff];
                    if (sz2 > 0) {
                        dst2[0] = '\0';
                        if (sz2 > 1) memset(dst2 + 1, 0, sz2 - 1);
                    }
                    offset += sz2;
                }
                break;
            }
        }

        /* Reject extra fields beyond schema (i.e., more commas/characters after expected fields). */
        if (*p != '\0') {
            free(out);
            return -1;
        }
    }

    *parsed_buffer = out;
    return 0;
}
